def amicable_numbers_sum(n):
    """
    Sum all amicable numbers from 1 to n.

    Amicable numbers are pairs of numbers where each number 
    equals the sum of the proper divisors of the other.
    """
    def sum_of_proper_divisors(num):
        """Calculate sum of proper divisors (divisors excluding the number itself)"""
        if num <= 1:
            return 0
        divisor_sum = 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                divisor_sum += i
                if i != num // i:
                    divisor_sum += num // i
        return divisor_sum

    amicable_set = set()

    for i in range(1, n + 1):
        sum_divisors_i = sum_of_proper_divisors(i)
        # Check if i and sum_divisors_i form an amicable pair
        if sum_divisors_i != i and sum_divisors_i <= n:
            sum_divisors_j = sum_of_proper_divisors(sum_divisors_i)
            if sum_divisors_j == i:
                amicable_set.add(i)

    return sum(amicable_set)
```

