def magic_square_test(matrix):
    """
    Calculate whether the matrix is a magic square.
    A magic square is a square matrix where the sum of each row,
    each column, and both diagonals are equal.
    """
    if not matrix or len(matrix) == 0:
        return False

    n = len(matrix)

    # Check if it's a square matrix
    for row in matrix:
        if len(row) != n:
            return False

    # Calculate the magic sum from the first row
    magic_sum = sum(matrix[0])

    # Check all rows
    for row in matrix:
        if sum(row) != magic_sum:
            return False

    # Check all columns
    for col in range(n):
        if sum(matrix[row][col] for row in range(n)) != magic_sum:
            return False

    # Check main diagonal (top-left to bottom-right)
    if sum(matrix[i][i] for i in range(n)) != magic_sum:
        return False

    # Check anti-diagonal (top-right to bottom-left)
    if sum(matrix[i][n - 1 - i] for i in range(n)) != magic_sum:
        return False

    return True
```

