def is_undulating(n):
    """
    Check whether the given number is undulating or not.
    An undulating number is a number where digits alternately rise and fall,
    or fall and rise (e.g., 1212121, 121, 989).

    Args:
        n: An integer to check

    Returns:
        True if the number is undulating, False otherwise
    """
    s = str(abs(n))

    # Numbers with less than 3 digits cannot be undulating
    if len(s) < 3:
        return False

    # Check if digits alternate between going up and down
    # or between going down and up

    # Determine the direction of first change
    if s[1] > s[0]:
        # First change is up, so pattern should be: up, down, up, down...
        for i in range(1, len(s)):
            if i % 2 == 1:  # Odd indices should be peaks (greater than neighbors)
                if not (s[i] > s[i-1] and (i == len(s) - 1 or s[i] > s[i+1])):
                    return False
            else:  # Even indices should be valleys (less than neighbors)
                if not (s[i] < s[i-1] and (i == len(s) - 1 or s[i] < s[i+1])):
                    return False
    elif s[1] < s[0]:
        # First change is down, so pattern should be: down, up, down, up...
        for i in range(1, len(s)):
            if i % 2 == 1:  # Odd indices should be valleys (less than neighbors)
                if not (s[i] < s[i-1] and (i == len(s) - 1 or s[i] < s[i+1])):
                    return False
            else:  # Even indices should be peaks (greater than neighbors)
                if not (s[i] > s[i-1] and (i == len(s) - 1 or s[i] > s[i+1])):
                    return False
    else:
        # First two digits are the same
        return False

    return True
```

